// IBM Plex Sans Condensed TTF font data for jsPDF
const IBM_NORMAL = ""
const IBM_BOLD = ""
const IBM_ITALIC = ""
const IBM_BOLDITALIC = ""

export function registerIBMPlexSans(doc) {
  doc.addFileToVFS("IBMPlexSans-normal.ttf", IBM_NORMAL)
  doc.addFont("IBMPlexSans-normal.ttf", "IBMPlexSans", "normal")
  doc.addFileToVFS("IBMPlexSans-bold.ttf", IBM_BOLD)
  doc.addFont("IBMPlexSans-bold.ttf", "IBMPlexSans", "bold")
  doc.addFileToVFS("IBMPlexSans-italic.ttf", IBM_ITALIC)
  doc.addFont("IBMPlexSans-italic.ttf", "IBMPlexSans", "italic")
  doc.addFileToVFS("IBMPlexSans-bolditalic.ttf", IBM_BOLDITALIC)
  doc.addFont("IBMPlexSans-bolditalic.ttf", "IBMPlexSans", "bolditalic")
}
